changeSet.sql:
CREATE TABLE IF NOT EXISTS app_tool_definition ( id BIGSERIAL PRIMARY KEY, code VARCHAR(64) NOT NULL UNIQUE, name VARCHAR(128) NOT NULL, summary VARCHAR(256) NOT NULL, description_markdown TEXT NOT NULL, category_code VARCHAR(64) NOT NULL, icon_key VARCHAR(64) NOT NULL, tags_json TEXT NOT NULL DEFAULT '[]', display_order INTEGER NOT NULL DEFAULT 0, enabled BOOLEAN NOT NULL DEFAULT TRUE, execution_mode VARCHAR(16) NOT NULL, renderer_code VARCHAR(64) NOT NULL, handler_code VARCHAR(64) NOT NULL, input_schema_json TEXT NOT NULL, default_values_json TEXT NOT NULL, result_schema_json TEXT NOT NULL, server_config_json TEXT NOT NULL, timeout_ms INTEGER, rate_limit_scope VARCHAR(24) NOT NULL DEFAULT 'NONE', rate_limit_max_requests INTEGER, rate_limit_window_seconds INTEGER, audit_enabled BOOLEAN NOT NULL DEFAULT FALSE, payload_limit_bytes INTEGER, created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP );
CREATE INDEX IF NOT EXISTS idx_app_tool_definition_enabled_order ON app_tool_definition(enabled, display_order, name, id);
CREATE TABLE IF NOT EXISTS app_tool_execution_log ( id BIGSERIAL PRIMARY KEY, execution_id VARCHAR(64) NOT NULL UNIQUE, tool_code VARCHAR(64) NOT NULL, user_id BIGINT, status VARCHAR(24) NOT NULL, duration_ms BIGINT, request_summary_json TEXT NOT NULL, response_summary_json TEXT NOT NULL, error_code VARCHAR(64), error_message VARCHAR(512), client_ip_masked VARCHAR(128), created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP );
CREATE INDEX IF NOT EXISTS idx_app_tool_execution_log_created ON app_tool_execution_log(created_at DESC, id DESC); CREATE INDEX IF NOT EXISTS idx_app_tool_execution_log_tool_code ON app_tool_execution_log(tool_code, created_at DESC); CREATE INDEX IF NOT EXISTS idx_app_tool_execution_log_user_id ON app_tool_execution_log(user_id, created_at DESC);
